create table performance_goals (goal_id varchar(36) not null, tenant_code varchar(64) not null, employee_id varchar(36) not null, title varchar(200) not null, description varchar(1000) null, target_date date null, status varchar(30) not null, created_at timestamp not null, updated_at timestamp not null, created_by varchar(120) not null, updated_by varchar(120) not null, primary key (goal_id));
create table performance_reviews (review_id varchar(36) not null, tenant_code varchar(64) not null, employee_id varchar(36) not null, review_cycle varchar(80) not null, status varchar(30) not null, manager_score decimal(5,2) null, employee_comments varchar(2000) null, manager_comments varchar(2000) null, created_at timestamp not null, updated_at timestamp not null, created_by varchar(120) not null, updated_by varchar(120) not null, primary key (review_id));
create index idx_perf_goals_tenant on performance_goals (tenant_code);
create index idx_perf_reviews_tenant on performance_reviews (tenant_code);
